# We will build the text programmatically to ensure perfection.
import re

def check_rules(text):
    if text == "":
        return True
    sentences = re.split(r'\.\s+[A-Z]', text)
    if len(sentences) < 3:
        raise ValueError(f"Paragraph has less than 3 sentences:\n{text}")
        
    forbidden = ["Dan", "Atau", "Tetapi", "Sehingga", "Karena", "Maka", "Namun", "Oleh karena itu", "Dengan demikian", "Selain itu", "Lalu", "Kemudian"]
    
    if text.startswith("Gambar"):
        raise ValueError(f"Paragraph cannot start with 'Gambar':\n{text}")
        
    raw_sentences = re.split(r'(?<=\.)\s+(?=[A-Z])', text)
    for s in raw_sentences:
        first_word = s.split(' ')[0].strip(',.')
        if first_word in forbidden:
            raise ValueError(f"Sentence starts with forbidden word '{first_word}':\n{s}")
            
    return True

content_structure = []
img_counter = 37

def add_heading_2(text):
    content_structure.append(("Heading 2", text))

def add_heading_3(text):
    content_structure.append(("Heading 3", text))

def add_para(text):
    text = text.strip()
    check_rules(text)
    content_structure.append(("Normal", text))

def add_image(title):
    global img_counter
    content_structure.append(("Placeholder", f"[Placeholder Gambar {img_counter}]"))
    clean_title = title + "." if not title.endswith(".") else title
    content_structure.append(("Caption", f"Gambar {img_counter}. {clean_title}"))
    img_counter += 1

